import machine, time, ubinascii, ujson
from umqtt import MQTTClient
from microcoapy import CoAPServer

# Define the server address and port to listen on.
SERVER = '192.168.0.3' # IP address of the device that runs the server code.
PORT = 5683 # Port number for CoAP communication.

# Define the resources exposed by the server.
TEMP_RESOURCE = '/sensors/temp'
LIGHT_RESOURCE = '/actuators/light'

# Define the payloads to be sent in response to GET requests.
TEMP_PAYLOAD = '{"temperature": 20}' # JSON format.
LIGHT_PAYLOAD = '{"brightness": 50}' # JSON format.

# Initialize the CoAP server and start listening on the defined port.
coapServer = CoAPServer(SERVER, PORT)
coapServer.start()

# Define a function to handle GET requests for TEMP_RESOURCE.
def handleGetTempRequest(request):
    return TEMP_PAYLOAD # Return the payload in JSON format.

# Define a function to handle PUT requests for TEMP_RESOURCE.
def handlePutTempRequest(request):
    # Parse the request body and extract the temperature value from it.
    parsedRequestBody = ujson.loads(request['payload'])
    tempValue = parsedRequestBody["temperature"]

    # Print out the received temperature value.
    print("Received temperature value: " + str(tempValue))

# Define a function to handle GET requests for LIGHT_RESOURCE.
def handleGetLightRequest(request):
    return LIGHT_PAYLOAD # Return the payload in JSON format.

# Define a function to handle PUT requests for LIGHT_RESOURCE.
def handlePutLightRequest(request):
    # Parse the request body and extract the brightness value from it.
    parsedRequestBody = ujson.loads(request['payload'])
    lightValue = parsedRequestBody["brightness"]

    # Print out the received brightness value.
    print("Received brightness value: " + str(lightValue))

# Register the GET handlers for TEMP_RESOURCE and LIGHT_RESOURCE.
coapServer.registerGetHandler(TEMP_RESOURCE, handleGetTempRequest)
coapServer.registerGetHandler(LIGHT_RESOURCE, handleGetLightRequest)

# Register the PUT handlers for TEMP_RESOURCE and LIGHT_RESOURCE.
coapServer.registerPutHandler(TEMP_RESOURCE, handlePutTempRequest)
coapServer.registerPutHandler(LIGHT_RESOURCE, handlePutLightRequest)

# Define a function to handle incoming CoAP messages.
def handleCoAPMessage(request):
    # Print out the received request type and URI path.
    print("Received request: " + str(request['type']) + ", " + request['uri-path'])

    # Check if the request is for TEMP_RESOURCE or LIGHT_RESOURCE.
    if (request['uri-path'] == TEMP_RESOURCE):
        handleGetTempRequest(request)
    elif (request['uri-path'] == LIGHT_RESOURCE):
        handleGetLightRequest(request)

# Register a handler to handle incoming CoAP messages.
coapServer.registerMessageHandler(handleCoAPMessage)

# Define a function that runs forever and handles incoming CoAP messages.
def main():
    # Wait for incoming CoAP messages.
    while True:
        coapServer.run()

# Run the main function.
main()